// ── XMP/GPano APP1 segment ────────────────────────────────────────────────

const XMP_PAYLOAD = Buffer.from(
  'http://ns.adobe.com/xap/1.0/\0' +
  '<x:xmpmeta xmlns:x="adobe:ns:meta/">' +
  '<rdf:RDF xmlns:rdf="http://www.w3.org/1999/02/22-rdf-syntax-ns#">' +
  '<rdf:Description rdf:about="" xmlns:GPano="http://ns.google.com/photos/1.0/panorama/">' +
  '<GPano:ProjectionType>equirectangular</GPano:ProjectionType>' +
  '<GPano:UsePanoramaViewer>True</GPano:UsePanoramaViewer>' +
  '<GPano:FullPanoWidthPixels>7776</GPano:FullPanoWidthPixels>' +
  '<GPano:FullPanoHeightPixels>3888</GPano:FullPanoHeightPixels>' +
  '</rdf:Description></rdf:RDF></x:xmpmeta>',
)

// ── EXIF APP1 with GPS ────────────────────────────────────────────────────

// We'll use piexifjs in the test files themselves; here we just make bare JPEGs
// and let the test suite verify the writer behavior.

// ── Build sample-360.jpg ─────────────────────────────────────────────────

function buildApp1(payload) {
  // APP1: FF E1 [len hi] [len lo] [payload]
  const len = payload.length + 2 // includes the 2 length bytes
  const seg = Buffer.alloc(4 + payload.length)
  seg[0] = 0xff; seg[1] = 0xe1
  seg[2] = (len >> 8) & 0xff
  seg[3] = len & 0xff
  payload.copy(seg, 4)
  return seg
}

// Insert XMP segment after JFIF APP0 in TINY_JPEG
// TINY_JPEG structure: SOI(2) + APP0 marker(2) + APP0 length(2) + APP0 data(14) = 20 bytes
const soiAndApp0 = TINY_JPEG.slice(0, 20) // FF D8 + FF E0 00 10 <14 bytes JFIF data>
const restOfJpeg = TINY_JPEG.slice(20)    // starts with FF DB (DQT)
const xmpApp1Seg = buildApp1(XMP_PAYLOAD)

const sample360 = Buffer.concat([soiAndApp0, xmpApp1Seg, restOfJpeg])
writeFileSync(join(__dir, 'sample-360.jpg'), sample360)
console.log('Written sample-360.jpg', sample360.length, 'bytes')

// sample-ref.jpg = plain tiny JPEG (GPS will be added by writer.ts)
writeFileSync(join(__dir, 'sample-ref.jpg'), TINY_JPEG)
console.log('Written sample-ref.jpg', TINY_JPEG.length, 'bytes')
